def check_service(host, port):
    """简单服务版本检测"""
    try:
        s = socket.socket()
        s.settimeout(3)
        s.connect((host, port))
        banner = s.recv(1024).decode(errors='ignore')
        s.close()
        return banner.strip()
    except:
        return None

